insert into experts (id, full_name, first_name, last_name, title, affiliation_type, partner_org, seniority_tier, years_experience, email, phone, bio_summary, notes, is_active) values
('784f80e0-e4b6-4eb1-a0f0-32aadc979f30', 'Dr. Aminata Niane Badiane', 'Aminata', 'Niane Badiane', 'Technical Director, African Resources Group (ARG)', 'partner', 'African Resources Group (ARG)', 'principal_expert', 45, 'anbadiane@gmail.com', '+221 77 630 15 27', 'Dr. Aminata Niane Badiane is a senior agricultural and natural resources management expert with over 40 years of professional experience, including 23 years with USAID/Senegal as Deputy Director of the Economic Growth Office and Agricultural/NRM Specialist. She has extensive experience in food security, agricultural research, environmental policy, and program management, and currently serves as Technical Director of ARG, leading consulting assignments for USAID, the World Bank, and other donors across West Africa.', NULL, true),
('7b8a35d5-72c2-4711-ae8b-75a82e174add', 'Samba Barry', 'Samba', 'Barry', 'International Consultant (Democracy, Human Rights, Governance and Peace Specialist)', 'partner', 'Independent International Consultant / OFNAC', 'principal_expert', 33, 'baccbarry@gmail.com', '+221 77 706 52 00', 'Samba Barry is a governance and peacebuilding expert with more than 30 years of experience designing and managing policies and programs in democracy, human rights, conflict resolution, and socioeconomic development. He held senior roles at USAID/Senegal (Deputy Director, DRGP Office), OHCHR West Africa, Oxfam GB (Country Director, Senegal), and currently serves as an independent international consultant and OFNAC board member.', NULL, true),
('358319c0-6543-48a0-8a6e-b67e8292eef9', 'Cécile Ngalounou Toche', 'Cécile', 'Ngalounou Toche', 'Statistician – M&E Specialist', 'partner', 'CORAF Executive Office / ARG', 'intermediary', 4, 'ceciletoche7@gmail.com', '+221 77 30 26 196', 'Cécile Ngalounou Toche is a statistical economist specializing in monitoring, evaluation, research, and learning (MERL), with expertise in survey design, sampling, statistical analysis, and impact evaluation of public policies. She has worked across multiple consulting assignments in Senegal and the broader West Africa region for CORAF, ARG, IP3-Conseil, AGRA, and FS4Africa.', NULL, true),
('2b7c7f6c-bddb-40ad-b1a4-e214ab32c78c', 'Dr. Abdrahmane Diallo', 'Abdrahmane', 'Diallo', 'Gender and Social Inclusion (GESI) and Senior Program Management Expert', 'partner', 'ARG', 'principal_expert', 35, 'abdrhdiallo@outlook.com', '+221 77 654 22 83', 'Dr. Abdrahmane Diallo is a gender and social inclusion expert with over 30 years of experience in strategic planning, project evaluation, public policy analysis, and gender mainstreaming. He spent 23 years at USAID/Senegal, including as Deputy Director of the Program Office, and has since worked as an independent consultant on gender, social inclusion, and cross-border security/community engagement projects.', NULL, true),
('720649b9-0eba-4abf-9824-88767e53b7a1', 'Dr. Moussa Diakhaté', 'Moussa', 'Diakhaté', 'Senior Health Information System Advisor', 'partner', 'Chemonics International (USAID)', 'principal_expert', 39, 'mkelekey@yahoo.fr', '+221 77 6565672', 'Dr. Moussa Diakhaté is a physician and public health information systems expert with nearly 40 years of experience, including as Head of Senegal''s National Health Information Service and senior advisor roles with USAID-funded health projects. He has extensive expertise in health information system design, M&E, demographic and health surveys, and health workforce data systems.', NULL, true),
('ad0447a4-abf5-4fc1-ba27-3c8a53bc9e87', 'Maria-Teresa Roberto', 'Maria-Teresa', 'Roberto', 'International Consultant, Acquisition & Assistance', 'partner', 'Jefferson Consulting Group (JCG)', 'principal_expert', 40, 'maiteroberto@gmail.com', '+221 77 634 37 12', 'Maria-Teresa "Maité" Roberto is a senior Acquisition, Assistance and Procurement professional with over 20 years of experience supporting complex USAID-funded programs, contract administration, and regulatory compliance. She has provided remote acquisition and assistance consulting to USAID missions in Senegal, Nepal, Pakistan, and Zambia, and holds FAC-C Professional Certification.', 'Sector mismatch — specializes in USAID acquisition & procurement; no controlled sector closely matches her specialization. Finance/Core Humanitarian Standards chosen as closest fit. Recommend manual review.', true),
('3ed082f3-d065-48ed-b213-a3ed5f8a6852', 'Honorat Sognon', 'Honorat', 'Sognon', 'Coach en mobilisation des ressources / Senior International Trainer', 'partner', 'Project HOPE', 'principal_expert', 26, 'honoratsognon@gmail.com', '+226 63 06 82 82', 'Honorat Sognon is a humanitarian operations and capacity-building expert with over 20 years of experience in project coordination, finance, HR, logistics, and security management, and over 10 years as a senior international trainer and coach. He has held senior support and country-director-level roles with Action Contre la Faim, Croix-Rouge Française, Institut Bioforce, and INSO.', NULL, true),
('07c2a5ed-7a6e-4ed0-83dd-a80bb00b393c', 'Abasse Ouedraogo', 'Abasse', 'Ouedraogo', 'Charge Programme Terrain', 'partner', 'Creative Associates International', 'intermediary', 6, 'abassedinho@gmail.com', '(00226)70017896', 'Abasse Ouedraogo is a specialist in food security, nutrition, rural development and local governance with roughly six years of experience supporting USAID- and Swiss Cooperation-funded programs in Burkina Faso. He has worked on inclusive governance, grants management, agricultural value chains, and resilience programming.', NULL, true),
('4de19a24-803f-4809-90b7-fb83c5bdfafe', 'Dr. Nanema Mathieu', 'Mathieu', 'Nanema', 'Senior Exploration Geologist / Executive Director', 'partner', 'Eburnean Discovery', 'principal_expert', 20, 'nanemageologue@gmail.com', '+22676207639', 'Dr. Nanema Mathieu is a world-class senior exploration geologist with over 20 years of experience in the extractive industry, having contributed to the discovery of major gold deposits including Kiaka (Burkina Faso), Massawa (Senegal), and Kibali (DRC). He spent 18+ years as Principal Exploration Geologist at Barrick Gold Corporation, and currently serves as Executive Director of Eburnean Discovery.', 'Sector mismatch — mining/exploration geology specialist; no controlled sector matches closely. "Economic recovery and livelihoods" chosen as weak fallback. Recommend manual review.', true),
('7c29ee3f-cb04-450a-b537-1421a6b4d5c0', 'Bè Bonkian', 'Bè', 'Bonkian', 'Expert SIG (GIS/Remote Sensing Specialist)', 'partner', 'Bureau Espace Geomatique Sarl', 'senior', 17, 'be.bonkian@2ie-edu.org', '+226 70 73 63 96', 'Be Bonkian is a GIS, cartography and remote sensing expert (Expert SIG) with extensive consulting experience across Burkina Faso since the mid-2000s. He has supported numerous donor-funded projects (World Bank, PNUD, USAID/NCBA CLUSA, FIDA, GIZ, Luxembourg Cooperation) in land-use mapping, resettlement action plans, and environmental and social impact studies.', NULL, true),
('88f38071-b272-40d8-a07f-da952dabe4db', 'Doufene Pagueure Raoul', 'Raoul', 'Doufene Pagueure', 'Expert-Comptable Judiciaire', 'partner', 'Independent (Expert-comptable Judiciaire)', 'intermediary', 9, 'doufeneraoul2@gmail.com', '+235 66-23-55-27', 'Doufene Pagueure Raoul is a Chadian judicial chartered accountant (Expert-comptable Judiciaire) accredited since 2017, with prior experience in procurement, logistics, and financial management roles. He has expertise in purchasing procedures, insurance, invoice control, financial analysis, and organizational management.', NULL, true),
('99b76a87-84b6-4e65-ad43-199b1b5a3369', 'Kuilga Emmanuel Yameogo', 'Emmanuel', 'Yameogo', 'Consultant Expert Minier / Directeur General de Bouroum SA', 'partner', 'Bouroum SA / Skygold Resources', 'principal_expert', 31, 'yamemma@gmail.com', '(226)76 47 45 33', 'Kuilga Emmanuel Yameogo is a mining engineer and surveyor with over 30 years of experience in Burkina Faso''s mining sector, having served as Director of Mines (2011-2018), Permanent Secretary of the National Mining Commission (2018-2023), and Technical Advisor to the Minister of Energy, Mines and Quarries. He currently works as an independent mining expert consultant.', 'Sector mismatch — mining engineering/surveying specialist; no controlled sector matches closely. Recommend manual review.', true),
('1a47d242-b31b-4052-9985-48ea4ff1972c', 'Allayam Ndikinan', 'Allayam', 'Ndikinan', 'Responsable Programmes/Projet & MEAL Manager', 'partner', 'Tearfund', 'senior', 17, 'pallayam@gmail.com', '+235 66 30 46 85', 'Allayam Ndikinan is a programs and MEAL manager with over a decade of experience in adaptive social protection and food security across humanitarian and development contexts in Chad and the Central African Republic. He has managed multi-donor portfolios (UNICEF, USAID, Tearfund, FHI 360) covering cash and voucher assistance, accountability mechanisms (CHS/CEA/GRM), and monitoring and evaluation.', NULL, true),
('bf62276f-e9cf-410f-a4b4-ad4c9c936f27', 'Diabate Adama', 'Adama', 'Diabate', 'Directeur du Controle des Marches publics et des Engagements Financiers', 'partner', 'Institut National de Sante Publique (INSP)', 'senior', 16, 'a.diabate51@gmail.com', '76510607', 'Diabate Adama is a Burkinabe public finance administrator currently serving as Director of Public Procurement and Financial Commitments Control at the Institut National de Sante Publique (INSP) since May 2024, having held the equivalent position at IRSAT from 2019-2024. He specializes in public procurement control, budget engagement verification, and financial audits.', NULL, true),
('f4668457-6e30-42b4-a792-b53e0ce34c59', 'Savadogo Gouwendé Moussa', 'Moussa', 'Savadogo Gouwendé', 'Juriste d''affaires / Médiateur professionnel certifié', 'partner', 'Centre d''Arbitrage, de Médiation et de Conciliation de Ouagadougou (CAMC-O)', 'senior', 16, 'sav_gouwend@yahoo.fr', '+226 76 31 65 64', 'Savadogo Gouwendé Moussa is a Burkinabe business lawyer and certified professional mediator specializing in OHADA business law, corporate taxation, and Alternative Dispute Resolution. He has worked since 2012 at the Ouagadougou Arbitration, Mediation and Conciliation Center (CAMC-O), and is a founding member of an Islamic microfinance institution (MICFIB SA).', 'Sector mismatch — business law / arbitration & mediation (ADR) specialist; no controlled sector matches closely. Finance/Economic recovery chosen as weak fallback. Recommend manual review.', true),
('cb72124b-18cc-4bc1-ae63-64723c33f3fe', 'Pallo Dapougdi Augustin', 'Augustin', 'Pallo', 'Ingénieur MQHSE / Lead Auditeur PECB ISO 45001 & ISO 9001', 'partner', 'Self-employed Consultant', 'junior', 5, 'palloaugustin@gmail.com', '+226 75 32 78 71', 'Pallo Dapougdi Augustin is a Burkinabe QHSE engineer and PECB-certified Lead Auditor for ISO 45001 and ISO 9001, specializing in occupational health, safety and environmental risk management in the construction, hydraulic works, electrical works, mining and banking sectors. He has led HSE compliance, audits, and training for World Bank-financed infrastructure projects.', 'Sector mismatch — QHSE (quality/health/safety/environment) engineering specialist for construction & mining sites; no controlled sector matches closely. Recommend manual review.', true),
('d68cd6ea-c2de-4a22-9f93-cdd0fb8877c5', 'Yonli Yempabou', 'Yempabou', 'Yonli', 'Économiste Gestionnaire — Chargé des Subventions et Appui aux Organisations locales', 'partner', 'ACSD Sarl', 'principal_expert', 25, 'julienyonli@gmail.com', '+226 76 61 45 59', 'Yonli Yempabou is a Burkinabe economist and management graduate (MBA, MSG) with over 25 years of experience in grants management, financial/administrative coordination, and local development across public administration and NGOs. He has coordinated grants for major USAID, BAD, EU and UNICEF-funded programs.', NULL, true),
('4c4ed032-713b-4eef-994e-334e80586325', 'Moussa Sawadogo', 'Moussa', 'Sawadogo', 'Enseignant universitaire en STIC / Consultant en communication', 'partner', 'Independent Consultant / Université de Ouagadougou', 'principal_expert', 30, 'elmous@yahoo.fr', '+226 66440202', 'Moussa Sawadogo is a Burkinabe communication expert and university lecturer with 30 years of experience in institutional communication strategy, crisis communication, media development, and peacebuilding/conflict prevention communication across West and Central Africa. He has led communication strategy assignments for USAID, EU, UNDP, UNESCO, and the World Bank.', NULL, true),
('61c87f44-4029-4b2a-83ce-88fcd88c53a1', 'Dr. Beguerang Topeur', 'Beguerang', 'Topeur', 'Consultant en statistique', 'partner', 'Independent Consultant', 'senior', 15, 'beguerang@yahoo.fr', '+235 65969976', 'Dr. Beguerang Topeur is a Chadian statistician and economist holding a doctorate in Economics, with 15 years of experience in quantitative and qualitative survey design, econometric modeling, and field data collection across Chad and West Africa. He has led numerous evaluation and survey missions for organizations including UNICEF, USAID/Africare, and the World Bank.', NULL, true),
('f8188b6c-6319-4c58-ac89-40274f7a1e43', 'Eric Wilfrid Yirin Zoure', 'Eric', 'Zoure', 'Secrétaire Permanent de l''ITIE', 'partner', 'Ministère de l''Economie et des Finances, Burkina Faso', 'principal_expert', 18, 'zewyre@yahoo.fr', '+226 70 76 56 90', 'Eric Wilfrid Yirin Zoure is a Burkinabe economist, planner and financial expert with over 18 years of experience in economic monitoring, development planning, and investment tracking for national and regional programs. He currently serves as Secrétaire Permanent of the Extractive Industries Transparency Initiative (ITIE) at Burkina Faso''s Ministry of Economy and Finance.', NULL, true),
('209e20ce-c4f1-4a53-8b3e-c1f5bc07b994', 'Tougma Adama', 'Adama', 'Tougma', 'Gestionnaire finance et administration, de Subvention, Logistique et la conformité', 'partner', 'TEARFUND', 'senior', 11, 'adama.tougma@yahoo.fr', '+226 75 10 39 19', 'Tougma Adama is a Burkinabe finance, HR and compliance manager with over 10 years of experience managing NGO financial operations, grants, payroll, and supply chain logistics in humanitarian and development contexts. She has held finance management and compliance roles at TEARFUND, MSH, and Christoffel Blinden Mission (CBM).', NULL, true),
('55f7e9e6-d536-408d-88b8-ea651205e1cd', 'Soro Ousseini', 'Ousseini', 'Soro', 'Directeur général des études et des statistiques sectorielles', 'partner', 'Ministère de la famille et de la solidarité, Burkina Faso', 'senior', 13, 'soroousseini@gmail.com', '00226 70 07 32 59', 'M. Soro Ousseini is a senior social protection and strategic planning specialist with over a decade of experience in Burkina Faso''s public administration, currently serving as Director-General of Studies and Sectoral Statistics at the Ministry of Family and Solidarity. He has led the design, monitoring and evaluation of national social protection policies and child protection strategies.', NULL, true),
('418908e0-e238-4e05-8b9a-1f08f17f118d', 'Sangla Mahamadi', 'Mahamadi', 'Sangla', 'Chef de Brigade de vérification', 'partner', 'Direction générale des impôts, Burkina Faso', 'principal_expert', 19, 'msangla2001@yahoo.fr', '(00226) 70 75 64 57', 'Mahamadi Sangla is a senior tax inspector with the Burkina Faso Directorate General of Taxes, specializing in corporate taxation, tax audits (including in the mining and telecommunications sectors), and tax dispute resolution. He has nearly two decades of experience designing and optimizing fiscal policy.', 'Sector mismatch — tax administration / fiscal audit specialist; only "Finance" loosely matches his expertise. Recommend manual review.', true),
('a258d5ca-b741-48e0-b1e3-494750eec13e', 'Al-Hassana Idriss Abakar', 'Idriss', 'Abakar', 'Consultant en finance et gestion des risques', 'partner', 'Cabinet ECO Finances et Trading', 'principal_expert', 18, 'abakare19@gmail.com', '+235 60-18-60-59', 'Al-Hassana Idriss Abakar is a finance professional from Chad with over 18 years of experience in audit, risk management, and financial analysis across banking, consulting, and public institutions. He has led financial audit missions for ministries and public enterprises in Côte d''Ivoire and worked on microfinance regulation for Chad''s Prime Minister''s Office.', NULL, true),
('b75b1bf9-3f93-49ed-aeff-7921575af572', 'Sore Boureima', 'Boureima', 'Sore', 'Expert en Planification Stratégique, Gouvernance institutionnelle, Gestion de Programmes et Développement Territorial', 'partner', 'Independent Consultant', 'senior', 17, 'boureima.sore@gmail.com', '+226 76 232 962', 'Boureima Soré is a senior strategic planning and programme management professional with over 17 years of experience coordinating complex donor-funded projects in Burkina Faso, working with the World Bank, AFD, the European Union, UN agencies, and the Peacebuilding Fund. He specializes in strategic plan development, results-based management, and territorial development.', NULL, true),
('371a7af3-e220-493d-8337-ca4983622247', 'Prof. Ebenezer Owusu-Addo', 'Ebenezer', 'Owusu-Addo', 'Associate Professor and Director, IRDIS, KNUST', 'partner', 'Kwame Nkrumah University of Science and Technology (KNUST)', 'principal_expert', 18, 'eowusu-addo.canr@knust.edu.gh', '+233501349036', 'Professor Ebenezer Owusu-Addo is an international development and evaluation specialist with 18 years of experience in monitoring, evaluation, and learning (MEL), currently serving as Associate Professor and Director of IRDIS at KNUST, Ghana. He holds a PhD in Public Health (Programme Evaluation) from Monash University and has led numerous impact evaluations for USAID, UNICEF, UNFPA, the World Bank, and the EU.', NULL, true),
('bc0a0535-b718-4007-83c6-a8df54a3b524', 'Prof. Paul Sarfo-Mensah', 'Paul', 'Sarfo-Mensah', 'Associate Professor, Bureau of Integrated Rural Development (BIRD), KNUST', 'partner', 'Kwame Nkrumah University of Science and Technology (KNUST)', 'principal_expert', 39, 'psarfomensah@gmail.com', '+233 24 3140500', 'Professor Paul Sarfo-Mensah is a veteran natural resources management and rural development expert with close to four decades of experience at KNUST''s Bureau of Integrated Rural Development. He holds a PhD in Natural Resources Management from the University of Greenwich and has led numerous evaluations and baseline studies for USAID, the World Bank, IFAD, the EU, and the Ghana Ministry of Finance.', NULL, true);
